import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const { login } = useAuth(); 
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(''); // I-clear ang error bago mag-try

    try {
      // 1. Hintayin ang response mula sa login function
      const loggedUser = await login(email, password);
      
      // 2. I-check kung successful at i-redirect base sa role
      if (loggedUser && loggedUser.role === 'admin') {
        navigate('/admin');
      } else if (loggedUser) {
        navigate('/home');
      }
    } catch (err) {
      // Dito lang papasok kung TALAGANG mali ang credentials o may server error
      setError(err.response?.data?.message || 'Login failed. Please try again.');
    }
  };

  return (
    <div className='login-page' style={{ padding: '50px', textAlign: 'center' }}>
      <div style={{ backgroundColor: 'white', padding: '40px', borderRadius: '15px', display: 'inline-block', boxShadow: '0 4px 15px rgba(0,0,0,0.1)' }}>
        <h2 style={{ color: '#ff69b4', marginBottom: '20px' }}>Login to Mi Ilao</h2>
        
        {error && <p style={{ color: 'red', marginBottom: '15px' }}>{error}</p>}
        
        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '15px', width: '300px' }}>
          <input 
            type='email' 
            placeholder='Email address'
            value={email} 
            onChange={e => setEmail(e.target.value)} 
            required 
            style={{ padding: '12px', borderRadius: '8px', border: '1px solid #ddd' }}
          />
          <input 
            type='password' 
            placeholder='Password'
            value={password} 
            onChange={e => setPassword(e.target.value)} 
            required
            style={{ padding: '12px', borderRadius: '8px', border: '1px solid #ddd' }}
          />
          <button type='submit' style={{ padding: '12px', backgroundColor: '#ff69b4', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>
            Login
          </button>
        </form>
        <p style={{ marginTop: '20px' }}>Don't have an account? <Link to='/register' style={{ color: '#ff69b4' }}>Register here</Link></p>
      </div>
    </div>
  );
};

export default LoginPage;
